from figma_flutter_agent.generator.dart.delimiters import replace_first_copywith_color
from figma_flutter_agent.generator.dart.file_parts import (
    relocate_directives_to_header,
    strip_directives_from_fragment,
)


def test_strip_directives_from_fragment() -> None:
    source = """class Screen {
  Widget build() {
    return Text('hi');
  }
}
import 'package:flutter/gestures.dart';
"""
    assert "import" not in strip_directives_from_fragment(source)


def test_relocate_directives_to_header() -> None:
    source = """// <auto-generated>
// </auto-generated>

import 'package:flutter/material.dart';

class GeneratedScreenShell {}

class Screen {
  Widget build() {
    return Text('x');
  }
}

import 'package:flutter/gestures.dart';
"""
    fixed = relocate_directives_to_header(source)
    lines = fixed.splitlines()
    gesture_idx = next(i for i, line in enumerate(lines) if "gestures.dart" in line)
    shell_idx = next(i for i, line in enumerate(lines) if "GeneratedScreenShell" in line)
    assert gesture_idx < shell_idx


def test_replace_copywith_color_handles_nested_color_ctor() -> None:
    source = (
        "TextSpan(text: 'x', style: Theme.of(context).textTheme.bodyLarge?.copyWith("
        "color: Color(0xFF000000), fontSize: 14.0, fontWeight: FontWeight.w700))"
    )
    patched, ok = replace_first_copywith_color(source, "Color(0xFF8E97FD)")
    assert ok
    assert "fontSize: 14.0" in patched
    assert "color: Color(0xFF8E97FD)" in patched
    assert "color: Color(0xFF000000)" not in patched
